frappe.ui.form.on('Budget Request', {
    // Custom function to perform calculations
    before_save: function(frm) {
        let months = [
            "january", "february", "march", "april", "may", "june", "july",
            "august", "september", "october", "november", "december"
        ];

        let total_quantity = 0;
        let total_amount = 0;

        frm.doc.item_summary = [];

        for (let month of months) {
            let month_total_quantity = 0;
            let month_total_amount = 0;

            frm.doc.budget_items_details.forEach((item) => {
                // Consider the value as zero if the status is not "Accepted"
                let quantity = item.status == "Accepted" ? (item[month] || 0) : 0;
                let amount = quantity * (item.expected_price || 0);

                month_total_quantity += quantity;
                month_total_amount += amount;
            });

            // Add summary for the month
            frm.add_child("item_summary", {
                month: month,
                total: month_total_amount,
                total_quantity: month_total_quantity
            });

            total_amount += month_total_amount;
            total_quantity += month_total_quantity;
        }

        frm.doc.total = total_amount;
        frm.doc.total_quantity = total_quantity;
        frm.refresh_fields();
    },
});

frappe.ui.form.on('Budget Items Details', {

    expected_price: function(frm, cdt, cdn) {
        var d = locals[cdt][cdn];
        var total_quantity = d.total_quantity || 0;
        var expected_price = d.expected_price || 0;

        if (!isNaN(expected_price) && !isNaN(total_quantity)) {
            var total = total_quantity * expected_price;
            frappe.model.set_value(cdt, cdn, 'total', total);
        } else {
            frappe.msgprint(__('Error: Expected Price or Total Quantity is not a valid number.'));
        }
    },

    total_quantity: function(frm, cdt, cdn) {
        var d = locals[cdt][cdn];
        var total_quantity = d.total_quantity || 0;
        var expected_price = d.expected_price || 0;

        if (!isNaN(expected_price) && !isNaN(total_quantity)) {
            var total = total_quantity * expected_price;
            frappe.model.set_value(cdt, cdn, 'total', total);
        } else {
            frappe.msgprint(__('Error: Expected Price or Total Quantity is not a valid number.'));
        }
    }    
});

frappe.ui.form.on('Budget Request', {
    // Parent form function - Fixed to handle sequential dialog processing
    insert_item_quantity: function(frm) {
        // Check if there are items in the child table
        if (!frm.doc.budget_items_details || frm.doc.budget_items_details.length === 0) {
            frappe.msgprint(__('Please add items to the budget details table first.'));
            return;
        }

        // Create a sequential dialog processor
        var current_item_index = 0;
        var items = frm.doc.budget_items_details;

        function show_dialog_for_item(index) {
            if (index >= items.length) {
                frappe.show_alert({
                    message: __('All items processed successfully'),
                    indicator: 'green'
                }, 5);
                return;
            }

            var d = items[index];
            var dialog = new frappe.ui.Dialog({
                title: __('Enter Monthly Budget Quantities for: ') + (d.item_name || d.item_code || 'Item ' + (index + 1)),
                fields: [
                    // Item Information Section
                    {
                        fieldname: "item_section",
                        fieldtype: "Section Break",
                        label: __("Item Information")
                    },
                    {
                        fieldname: "item_code",
                        fieldtype: "Link",
                        label: __("Item Code"),
                        options: "Item",
                        reqd: 1
                    },
                    {
                        fieldname: "column_break_item_1",
                        fieldtype: "Column Break"
                    },
                    {
                        fieldname: "expected_price",
                        fieldtype: "Float",
                        label: __("Expected Price"),
                        precision: 2
                    },
                    {
                        fieldname: "column_break_item_2",
                        fieldtype: "Column Break"
                    },
                    {
                        fieldname: "expense_account",
                        fieldtype: "Link",
                        label: __("Expense Account"),
                        options: "Account",
                        get_query: function() {
                            return {
                                filters: {
                                    "company":  frappe.defaults.get_user_default("Company"),  
                                    "report_type": "Profit and Loss",
                                    "is_group": 0
                                }
                            };
                        }
                    },
                    // Monthly Quantities Section
                    {
                        fieldname: "monthly_section",
                        fieldtype: "Section Break",
                        label: __("Monthly Quantities")
                    },
                    { fieldname: "january", fieldtype: 'Float', label: __("January") },
                    { fieldname: "july", fieldtype: "Float", label: __("July") },
                    { fieldname: "column_break_1", fieldtype: 'Column Break' },
                    { fieldname: "february", fieldtype: "Float", label: __("February") },
                    { fieldname: "august", fieldtype: "Float", label: __("August") },
                    { fieldname: "column_break_2", fieldtype: 'Column Break' },
                    { fieldname: "march", fieldtype: "Float", label: __("March") },
                    { fieldname: "september", fieldtype: "Float", label: __("September") },
                    { fieldname: "column_break_3", fieldtype: 'Column Break' },
                    { fieldname: "april", fieldtype: "Float", label: __("April") },
                    { fieldname: "october", fieldtype: "Float", label: __("October") },
                    { fieldname: "column_break_4", fieldtype: 'Column Break' },
                    { fieldname: "may", fieldtype: "Float", label: __("May") },
                    { fieldname: "november", fieldtype: 'Float', label: __("November") },
                    { fieldname: "column_break_5", fieldtype: 'Column Break' },
                    { fieldname: "june", fieldtype: "Float", label: __("June") },
                    { fieldname: "december", fieldtype: "Float", label: __("December") },
                    // Summary Section
                    {
                        fieldname: "summary_section",
                        fieldtype: "Section Break",
                        label: __("Summary")
                    },
                    {
                        fieldname: "total_quantity",
                        fieldtype: "Float",
                        label: __("Total Quantity"),
                        read_only: 1
                    },
                    {
                        fieldname: "column_break_summary",
                        fieldtype: "Column Break"
                    },
                    {
                        fieldname: "total_amount",
                        fieldtype: "Currency",
                        label: __("Total Amount"),
                        read_only: 1
                    }
                ],
                size: 'extra-large'
            });

            // Pre-fill values
            dialog.set_values({
                'item_code': d.item_code || '',
                'expected_price': d.expected_price || 0.00,
                'expense_account': d.expense_account || '',
                'january': d.january || 0.00,
                'february': d.february || 0.00, 
                'march': d.march || 0.00,
                'april': d.april || 0.00,
                'may': d.may || 0.00,
                'june': d.june || 0.00,
                'july': d.july || 0.00,
                'august': d.august || 0.00,
                'september': d.september || 0.00,
                'october': d.october || 0.00,
                'november': d.november || 0.00,
                'december': d.december || 0.00,
                'total_quantity': d.total_quantity || 0.00,
                'total_amount': (d.total_quantity || 0) * (d.expected_price || 0)
            });

            // Add real-time calculation when monthly quantities change
            var month_fields = ['january','february','march','april','may','june',
                              'july','august','september','october','november','december'];

            month_fields.forEach(function(field) {
                dialog.fields_dict[field].$input.on('change', function() {
                    calculate_totals();
                });
            });

            dialog.fields_dict.expected_price.$input.on('change', function() {
                calculate_totals();
            });

            function calculate_totals() {
                var total_qty = 0;
                month_fields.forEach(function(field) {
                    var val = parseFloat(dialog.get_value(field)) || 0;
                    total_qty += val;
                });
                var expected_price = parseFloat(dialog.get_value('expected_price')) || 0;
                var total_amount = total_qty * expected_price;

                dialog.set_value('total_quantity', total_qty);
                dialog.set_value('total_amount', total_amount);
            }

            // Primary action (Update and Next/Finish)
            dialog.set_primary_action(index === items.length - 1 ? __('Finish') : __('Next'), function() {
                var item_code = dialog.get_value('item_code');
                var expected_price = dialog.get_value('expected_price');
                var expense_account = dialog.get_value('expense_account');

                // Validate required fields
                if (!item_code) {
                    frappe.msgprint(__('Please select an Item Code'));
                    return;
                }

                // Update item information
                frappe.model.set_value(d.doctype, d.name, 'item_code', item_code);
                frappe.model.set_value(d.doctype, d.name, 'expected_price', expected_price || 0);
                frappe.model.set_value(d.doctype, d.name, 'expense_account', expense_account || '');

                // Update monthly quantities
                var fields = [
                    'january','february','march','april','may','june',
                    'july','august','september','october','november','december'
                ];
                var total_quantity = 0;

                fields.forEach(function(fieldname) {
                    var value = parseFloat(dialog.get_value(fieldname)) || 0;
                    frappe.model.set_value(d.doctype, d.name, fieldname, value);
                    total_quantity += value;
                });

                frappe.model.set_value(d.doctype, d.name, 'total_quantity', total_quantity);

                // Calculate and set total amount
                var total_amount = total_quantity * (expected_price || 0);
                frappe.model.set_value(d.doctype, d.name, 'total', total_amount);

                frappe.show_alert({
                    message: __('Updated: ') + (d.item_name || item_code || 'Item ' + (index + 1)),
                    indicator: 'green'
                }, 2);

                dialog.hide();
                // Show next item dialog
                show_dialog_for_item(index + 1);
            });

            // Add Skip button using add_custom_action
            dialog.add_custom_action(__('Skip'), function() {
                dialog.hide();
                // Show next item dialog
                show_dialog_for_item(index + 1);
            });

            dialog.show();
        }

        // Start with the first item
        show_dialog_for_item(0);
    }
});

frappe.ui.form.on("Purchase Order", {
    async validate(frm) {
        console.log('validate')
        // Prevent multiple simultaneous validations
        if (frm._budget_validating) {
            console.log("Budget validation already in progress");
            return frm._budget_validation_result || false;
        }

        // Basic validation checks
        if (!await performBasicValidation(frm)) {
            return false;
        }

        // Budget validation
        try {
            frm._budget_validating = true;
            const budgetValidation = await validateBudget(frm);
            console.log("✅ validateBudget finished");
            frm._budget_validation_result = budgetValidation;
            console.log("✅ validateBudget finished");
            console.log("budgetValidation Response:", frm._budget_validation_result);
            console.log("✅ validateBudget finished");
            return budgetValidation;
        } catch (error) {
            console.log(" error type :", error.type);
            // frappe.validated = false;
            // frappe.msgprint({
            //     title: __("Budget Validation Error"),
            //     message: error.message || __("An error occurred during budget validation"),
            //     indicator: "red",
            // });
            return false;
        } finally {
            frm._budget_validating = false;

        }
    },

    async refresh(frm) {
        // Clear validation flags on refresh
        frm._budget_validating = false;
        frm._budget_validation_result = null;

        // Add custom button to show budget summary
        if (frm.doc.docstatus === 0 && frm.doc.cost_center) {
            frm.add_custom_button(__('Show Budget Summary'), function() {
                showBudgetSummary(frm);
            }, __("Budget"));

            // Add debug button
            frm.add_custom_button(__('Debug Budget Validation'), function() {
                debugBudgetValidation(frm);
            }, __("Budget"));
        }
    }
});

/**
 * Perform basic form validation
 */
async function performBasicValidation(frm) {
    const transactionDate = frm.doc.transaction_date;
    const itemsTable = frm.doc.items;

    if (!transactionDate) {
        frappe.msgprint({
            title: __("Transaction Date"),
            message: __("Transaction Date is required"),
            indicator: 'red',
        });
        frappe.validated = false;
        frm.scroll_to_field('transaction_date');
        return false;
    }

    if (!itemsTable || itemsTable.length === 0) {
        frappe.msgprint({
            title: __("Items Table"),
            message: __("Items table cannot be empty"),
            indicator: 'red',
        });
        frappe.validated = false;
        frm.scroll_to_field('items');
        return false;
    }

    // Validate that all items have required fields
    for (let i = 0; i < itemsTable.length; i++) {
        const item = itemsTable[i];
        if (!item.cost_center) {
            frappe.msgprint({
                title: __("Missing Cost Center"),
                message: __("Cost Center is required for item in row {0}", [i + 1]),
                indicator: 'red',
            });
            frappe.validated = false;
            return false;
        }
        if (!item.expense_account) {
            frappe.msgprint({
                title: __("Missing Expense Account"),
                message: __("Expense Account is required for item in row {0}", [i + 1]),
                indicator: 'red',
            });
            frappe.validated = false;
            return false;
        }
    }

    return true;
}

/**
 * Main budget validation function
 */
async function validateBudget(frm) {
    try {
        console.log("🔍 Starting budget validation...");

        const response = await frappe.call({
            method: "budget.budget.api.purchase_order.validate_purchase_order_budget",
            args: {
                po_doc: {
                    name: frm.doc.name,
                    transaction_date: frm.doc.transaction_date,
                    cost_center: frm.doc.cost_center
                },
                items: frm.doc.items
            }
        });
         console.log("✅ Vresponse:", response);
        if (!response.message.success && response.message.type !== "validationMonthlyBudgetError") {
            throw new Error(response.message.error || "System Error during budget validation");
        }


        const validationResult = response.message.validation_result;
        console.log("✅ Validation Result:", validationResult);
        console.log("🔍 Stops count:", validationResult.stops?.length || 0);
        console.log("🔍 Warnings count:", validationResult.warnings?.length || 0);

        // Log the actual items to see if there are duplicates
        if (validationResult.stops) {
            console.log("🔍 Stop items:", validationResult.stops);
        }
        if (validationResult.warnings) {
            console.log("🔍 Warning items:", validationResult.warnings);
        }

        // Handle budget stops (will prevent submission)
        if (validationResult.has_stops) {
            // Remove duplicates based on cost_center + expense_account combination
            const uniqueStops = removeDuplicateValidations(validationResult.stops);
            console.log("🔍 Unique stops after deduplication:", uniqueStops);

            const stopMessage = formatBudgetMessage(uniqueStops, "Stop");
            frappe.msgprint({
                title: __("Monthly Budget Exceeded - Submission Blocked"),
                message: stopMessage,
                indicator: "red"
            });
            frappe.validated = false;
            return validationResult;
        }

        // Handle budget warnings (will show warning but allow submission)
        if (validationResult.has_warnings) {
            // Remove duplicates based on cost_center + expense_account combination
            const uniqueWarnings = removeDuplicateValidations(validationResult.warnings);
            console.log("🔍 Unique warnings after deduplication:", uniqueWarnings);

            const warningMessage = formatBudgetMessage(uniqueWarnings, "Warning");
            // frappe.msgprint({
            //     title: __("Monthly Budget Warning"),
            //     message: warningMessage,
            //     indicator: "orange"
            // });
            // frappe.validated = true;
             frappe.confirm(
                warningMessage,
                () => {
                    // ✅ User confirmed → continue save
                    frappe.validated = true;
                },
                () => {
                    // ❌ User cancelled → stop save
                    frappe.validated = false;
                    frm.dirty();
                },
                __("Monthly Budget Warning")
            );
        }

        console.log("✅ Budget validation completed successfully");
        return validationResult;

    } catch (error) {
        console.error("❌ Budget validation failed:", error);
        frappe.validated = false;
        throw error;
    }
}

/**
 * Format budget validation messages
 */
function formatBudgetMessage(items, messageType) {
    const icon = messageType === "Stop" ? "⛔️" : "⚠️";

    return items.map((item, index) => `
        <div class="budget-item-message" style="margin-bottom: 15px; padding: 10px; border: 1px solid #ddd; border-radius: 5px;">
            <div style="font-weight: bold; margin-bottom: 10px;">
                ${icon} Budget ${messageType} - Account ${index + 1}
                ${item.item_count && item.item_count > 1 ? `(${item.item_count} items)` : ''}
            </div>
            <table class="table table-bordered table-sm">
                <tr>
                    <td><strong>Item:</strong></td>
                    <td>${item.item_code}${item.item_count && item.item_count > 1 ? ` (and ${item.item_count - 1} other items)` : ''}</td>
                </tr>
                <tr>
                    <td><strong>Cost Center:</strong></td>
                    <td>${item.cost_center}</td>
                </tr>
                <tr>
                    <td><strong>Account:</strong></td>
                    <td>${item.expense_account}</td>
                </tr>
                <tr>
                    <td><strong>Month:</strong></td>
                    <td>${item.month}</td>
                </tr>
                <tr>
                    <td><strong>Monthly Budget:</strong></td>
                    <td>${formatCurrency(item.monthly_budget)}</td>
                </tr>
                <tr>
                    <td><strong>Already Spent:</strong></td>
                    <td>${formatCurrency(item.already_spent)}</td>
                </tr>
                <tr>
                    <td><strong>Current Amount:</strong></td>
                    <td>${formatCurrency(item.current_amount)}</td>
                </tr>
                <tr>
                    <td><strong>Total After PO:</strong></td>
                    <td style="color: red; font-weight: bold;">${formatCurrency(item.total_after_po)}</td>
                </tr>
                <tr>
                    <td><strong>Excess Amount:</strong></td>
                    <td style="color: red; font-weight: bold;">${formatCurrency(item.excess_amount)}</td>
                </tr>
                <tr>
                    <td><strong>Budget Document:</strong></td>
                    <td>${item.budget_name}</td>
                </tr>
            </table>
        </div>
    `).join("");
}

/**
 * Show budget summary dialog
 */
async function showBudgetSummary(frm) {
    if (!frm.doc.transaction_date) {
        frappe.msgprint(__("Please set transaction date first"));
        return;
    }

    try {
        // Get unique cost centers from items
        const costCenters = [...new Set(frm.doc.items.map(item => item.cost_center).filter(cc => cc))];

        if (costCenters.length === 0) {
            frappe.msgprint(__("No cost centers found in items"));
            return;
        }

        const fiscalYear = frm.doc.transaction_date.split('-')[0];

        // Get budget summary for each cost center
        const summaries = await Promise.all(
            costCenters.map(async (costCenter) => {
                const response = await frappe.call({
                    method: "budget.budget.api.purchase_order.get_budget_summary",
                    args: {
                        cost_center: costCenter,
                        fiscal_year: fiscalYear,
                        transaction_date: frm.doc.transaction_date
                    }
                });
                return response.message;
            })
        );

        // Display budget summary in a dialog
        displayBudgetSummaryDialog(summaries);

    } catch (error) {
        console.error("Error getting budget summary:", error);
        frappe.msgprint({
            title: __("Error"),
            message: __("Failed to get budget summary: {0}", [error.message]),
            indicator: "red"
        });
    }
}

/**
 * Display budget summary in a dialog
 */
function displayBudgetSummaryDialog(summaries) {
    let content = "<div class='budget-summary-container'>";

    summaries.forEach(summary => {
        if (!summary.success) {
            content += `<div class="alert alert-warning">Error loading budget for cost center</div>`;
            return;
        }

        content += `
            <div class="budget-cost-center-section">
                <h4>Cost Center: ${summary.cost_center}</h4>
                <p><strong>Month:</strong> ${summary.month}</p>

                <table class="table table-bordered table-sm">
                    <thead>
                        <tr>
                            <th>Account</th>
                            <th>Annual Budget</th>
                            <th>Monthly Allocation</th>
                            <th>Spent This Month</th>
                            <th>Remaining</th>
                            <th>Status</th>
                        </tr>
                    </thead>
                    <tbody>
        `;

        summary.summary.forEach(account => {
            const remaining = account.remaining;
            const utilizationPercent = ((account.spent_amount / account.monthly_allocation) * 100).toFixed(1);
            let statusClass = 'text-success';
            let statusText = 'Good';

            if (remaining < 0) {
                statusClass = 'text-danger';
                statusText = 'Exceeded';
            } else if (utilizationPercent > 80) {
                statusClass = 'text-warning';
                statusText = 'High Usage';
            }

            content += `
                <tr>
                    <td>${account.account}</td>
                    <td>${formatCurrency(account.budget_amount)}</td>
                    <td>${formatCurrency(account.monthly_allocation)}</td>
                    <td>${formatCurrency(account.spent_amount)}</td>
                    <td class="${statusClass}">${formatCurrency(remaining)}</td>
                    <td class="${statusClass}">${statusText} (${utilizationPercent}%)</td>
                </tr>
            `;
        });

        content += `
                    </tbody>
                </table>
            </div>
            <hr>
        `;
    });

    content += "</div>";

    const dialog = new frappe.ui.Dialog({
        title: __("Budget Summary"),
        size: 'extra-large',
        fields: [
            {
                fieldtype: 'HTML',
                fieldname: 'budget_summary',
                options: content
            }
        ],
        primary_action_label: __("Close"),
        primary_action: function() {
            dialog.hide();
        }
    });

    dialog.show();
}

/**
 * Format currency values
 */
function formatCurrency(amount) {
    return format_currency(amount, frappe.defaults.get_default("currency"));
}

/**
 * Item-level validation
 */
frappe.ui.form.on("Purchase Order Item", {
    cost_center: function(frm, cdt, cdn) {
        // Auto-validate budget when cost center changes
        const item = locals[cdt][cdn];
        if (item.cost_center && item.expense_account && item.amount) {
            validateSingleItem(frm, item);
        }
    },

    expense_account: function(frm, cdt, cdn) {
        // Auto-validate budget when expense account changes
        const item = locals[cdt][cdn];
        if (item.cost_center && item.expense_account && item.amount) {
            validateSingleItem(frm, item);
        }
    },

    amount: function(frm, cdt, cdn) {
        // Auto-validate budget when amount changes
        const item = locals[cdt][cdn];
        if (item.cost_center && item.expense_account && item.amount) {
            validateSingleItem(frm, item);
        }
    }
});

/**
 * Validate single item against budget (for real-time feedback)
 */
async function validateSingleItem(frm, item) {

    if (!frm.doc.transaction_date) return;

    try {
        const response = await frappe.call({
            method: "budget.budget.api.purchase_order.validate_purchase_order_budget",
            args: {
                po_doc: {
                    name: frm.doc.name,
                    transaction_date: frm.doc.transaction_date
                },
                items: [item] // Validate just this item
            }
        });

        if (response.message.success) {
            const validationResult = response.message.validation_result;

            if (validationResult.has_stops || validationResult.has_warnings) {
                const allItems = [...(validationResult.stops || []), ...(validationResult.warnings || [])];
                const itemResult = allItems.find(result => 
                    result.item_code === item.item_code && 
                    result.cost_center === item.cost_center
                );

                if (itemResult) {
                    const messageType = validationResult.has_stops ? "error" : "warning";
                    frappe.show_alert({
                        message: `Budget ${messageType}: ${item.item_code} - Remaining: ${formatCurrency(itemResult.monthly_budget - itemResult.already_spent)}`,
                        indicator: messageType === "error" ? "red" : "orange"
                    }, 5);
                }
            }
        }
    } catch (error) {
        console.log("Real-time validation error:", error);
        // Don't show error to user for real-time validation
    }
}

/**
 * Remove duplicate validation messages based on cost_center + expense_account
 */
function removeDuplicateValidations(validationItems) {
    if (!validationItems || validationItems.length === 0) {
        return [];
    }

    const seen = new Set();
    const unique = [];

    for (const item of validationItems) {
        const key = `${item.cost_center}||${item.expense_account}`;
        if (!seen.has(key)) {
            seen.add(key);
            unique.push(item);
        } else {
            console.log(`🔍 Removing duplicate validation for: ${key}`);
        }
    }

    return unique;
}

